INSERT INTO quiz (id, king_id, difficulty, reward, time_limit_sec, question, choices, explanation) VALUES
('q_king01_01', 'king_ramkhamhaeng', 'easy', 50, 20, 'พ่อขุนรามคำแหงมหาราชทรงประดิษฐ์สิ่งใดที่คนไทยยังใช้จนถึงปัจจุบัน?', '[{"text":"อักษรไทย","correct":true},{"text":"เลขโรมัน","correct":false},{"text":"ปฏิทินจันทรคติ","correct":false},{"text":"ธงชาติ","correct":false}]', 'ทรงประดิษฐ์ ''ลายสือไท'' เมื่อ พ.ศ. 1826 เป็นต้นแบบของอักษรไทยในปัจจุบัน'),
('q_king02_01', 'king_naresuan', 'medium', 70, 20, 'สมเด็จพระนเรศวรมหาราชทรงมีชัยชนะครั้งสำคัญด้วยการรบรูปแบบใด?', '[{"text":"ยุทธหัตถี (ชนช้าง)","correct":true},{"text":"รบทางเรือ","correct":false},{"text":"ยิงปืนใหญ่","correct":false},{"text":"รบด้วยม้า","correct":false}]', 'ทรงกระทำยุทธหัตถีชนะพระมหาอุปราชา เมื่อ พ.ศ. 2135'),
('q_king04_01', 'king_taksin', 'medium', 70, 20, 'สมเด็จพระเจ้าตากสินมหาราชทรงสถาปนาราชธานีใดหลังกอบกู้เอกราช?', '[{"text":"กรุงธนบุรี","correct":true},{"text":"กรุงศรีอยุธยา","correct":false},{"text":"กรุงสุโขทัย","correct":false},{"text":"กรุงเทพมหานคร","correct":false}]', 'ทรงสถาปนากรุงธนบุรีเป็นราชธานีหลังเสียกรุงศรีอยุธยาครั้งที่ 2'),
('q_king01_02', 'king_ramkhamhaeng', 'medium', 70, 20, 'หลักฐานสำคัญที่บันทึกเรื่องราวสมัยพ่อขุนรามคำแหงคือข้อใด?', '[{"text":"ศิลาจารึกหลักที่ 1","correct":true},{"text":"พงศาวดารกรุงศรีอยุธยา","correct":false},{"text":"ไตรภูมิพระร่วง","correct":false},{"text":"กฎหมายตราสามดวง","correct":false}]', 'ศิลาจารึกหลักที่ 1 บันทึกเรื่องราวความเป็นอยู่และการปกครองสมัยสุโขทัย'),
('q_king02_02', 'king_naresuan', 'easy', 50, 20, 'สมเด็จพระนเรศวรมหาราชทรงกอบกู้เอกราชของกรุงศรีอยุธยาจากชาติใด?', '[{"text":"พม่า","correct":true},{"text":"เขมร","correct":false},{"text":"ฝรั่งเศส","correct":false},{"text":"จีน","correct":false}]', 'ทรงประกาศอิสรภาพจากพม่าเมื่อ พ.ศ. 2127'),
('q_king03_01', 'king_narai', 'easy', 50, 20, 'รัชสมัยสมเด็จพระนารายณ์มหาราชทรงเจริญสัมพันธไมตรีกับชาติใดเป็นพิเศษ?', '[{"text":"ฝรั่งเศส","correct":true},{"text":"ญี่ปุ่น","correct":false},{"text":"อังกฤษ","correct":false},{"text":"รัสเซีย","correct":false}]', 'ทรงส่งราชทูตโกษาปานไปเจริญสัมพันธไมตรีกับฝรั่งเศสในสมัยพระเจ้าหลุยส์ที่ 14'),
('q_king03_02', 'king_narai', 'hard', 100, 25, 'ราชทูตที่สมเด็จพระนารายณ์ทรงส่งไปฝรั่งเศสมีชื่อว่าอะไร?', '[{"text":"ออกพระวิสูตรสุนทร (โกษาปาน)","correct":true},{"text":"เจ้าพระยาโกษาเหล็ก","correct":false},{"text":"ออกญาเสนาภิมุข","correct":false},{"text":"เจ้าพระยาบวรราชนายก","correct":false}]', 'โกษาปานเป็นหัวหน้าคณะราชทูตไปเข้าเฝ้าพระเจ้าหลุยส์ที่ 14 เมื่อ พ.ศ. 2229'),
('q_king04_02', 'king_taksin', 'hard', 100, 25, 'กรุงศรีอยุธยาเสียแก่พม่าครั้งที่ 2 ในปีใด ก่อนที่พระเจ้าตากสินจะกอบกู้เอกราช?', '[{"text":"พ.ศ. 2310","correct":true},{"text":"พ.ศ. 2135","correct":false},{"text":"พ.ศ. 2112","correct":false},{"text":"พ.ศ. 2325","correct":false}]', 'กรุงศรีอยุธยาเสียครั้งที่ 2 เมื่อ พ.ศ. 2310 และพระเจ้าตากสินทรงกอบกู้ได้ในปีเดียวกัน'),
('q_king05_01', 'king_rama1', 'easy', 50, 20, 'รัชกาลที่ ๑ ทรงสถาปนาราชธานีใหม่ชื่อว่าอะไร?', '[{"text":"กรุงเทพมหานคร (กรุงรัตนโกสินทร์)","correct":true},{"text":"กรุงธนบุรี","correct":false},{"text":"กรุงศรีอยุธยา","correct":false},{"text":"กรุงสุโขทัย","correct":false}]', 'ทรงสถาปนากรุงรัตนโกสินทร์เป็นราชธานีเมื่อ พ.ศ. 2325 และตั้งราชวงศ์จักรี'),
('q_king05_02', 'king_rama1', 'medium', 70, 20, 'ประมวลกฎหมายที่รัชกาลที่ ๑ โปรดให้ชำระขึ้นใหม่มีชื่อว่าอะไร?', '[{"text":"กฎหมายตราสามดวง","correct":true},{"text":"กฎหมายลักษณะอาญา","correct":false},{"text":"พระธรรมนูญ","correct":false},{"text":"กฎมณเฑียรบาล","correct":false}]', 'ทรงโปรดให้ชำระกฎหมายและประทับตรา 3 ดวง จึงเรียก ''กฎหมายตราสามดวง'''),
('q_king06_01', 'king_rama4', 'easy', 50, 20, 'รัชกาลที่ ๔ ได้รับการยกย่องให้เป็น ''พระบิดา'' ของศาสตร์ใด?', '[{"text":"วิทยาศาสตร์ไทย","correct":true},{"text":"การแพทย์ไทย","correct":false},{"text":"ดนตรีไทย","correct":false},{"text":"กฎหมายไทย","correct":false}]', 'ทรงได้รับยกย่องเป็น ''พระบิดาแห่งวิทยาศาสตร์ไทย'' จากการคำนวณสุริยุปราคาที่หว้ากอ'),
('q_king06_02', 'king_rama4', 'hard', 100, 25, 'รัชกาลที่ ๔ ทรงคำนวณการเกิดสุริยุปราคาเต็มดวงได้อย่างแม่นยำที่ตำบลใด?', '[{"text":"หว้ากอ จ.ประจวบคีรีขันธ์","correct":true},{"text":"บางปะอิน จ.พระนครศรีอยุธยา","correct":false},{"text":"ปากน้ำ จ.สมุทรปราการ","correct":false},{"text":"หัวหิน จ.ประจวบคีรีขันธ์","correct":false}]', 'ทรงคำนวณและเสด็จทอดพระเนตรสุริยุปราคาที่หว้ากอเมื่อ พ.ศ. 2411'),
('q_king07_01', 'king_rama5', 'easy', 50, 20, 'พระราชกรณียกิจสำคัญของรัชกาลที่ ๕ ที่ทำให้ได้พระนาม ''พระปิยมหาราช'' คือข้อใด?', '[{"text":"การเลิกทาส","correct":true},{"text":"การสร้างพระบรมมหาราชวัง","correct":false},{"text":"การประดิษฐ์อักษรไทย","correct":false},{"text":"การทำยุทธหัตถี","correct":false}]', 'ทรงเลิกทาสโดยไม่เสียเลือดเนื้อ และปฏิรูปประเทศให้ทันสมัย'),
('q_king07_02', 'king_rama5', 'medium', 70, 20, 'สาธารณูปโภคสมัยใหม่ใดที่ริเริ่มขึ้นในรัชสมัยรัชกาลที่ ๕?', '[{"text":"การรถไฟและไปรษณีย์โทรเลข","correct":true},{"text":"รถไฟฟ้าใต้ดิน","correct":false},{"text":"สนามบินสุวรรณภูมิ","correct":false},{"text":"โทรทัศน์","correct":false}]', 'ทรงริเริ่มกิจการรถไฟ ไปรษณีย์ โทรเลข และสาธารณูปโภคสมัยใหม่หลายอย่าง');
INSERT INTO knowledge (id, king_id, title, body, question, choices) VALUES
('k_king01_01', 'king_ramkhamhaeng', 'อักษรไทยกำเนิดที่สุโขทัย', 'พ่อขุนรามคำแหงทรงประดิษฐ์ลายสือไทเมื่อ พ.ศ. 1826 ปรากฏหลักฐานในศิลาจารึกหลักที่ 1 ซึ่งบันทึกเรื่องราวความเป็นอยู่ของชาวสุโขทัย', 'พ่อขุนรามคำแหงทรงประดิษฐ์อักษรไทย (ลายสือไท) เมื่อ พ.ศ. ใด?', '[{"text":"พ.ศ. 1826","correct":true},{"text":"พ.ศ. 2310","correct":false},{"text":"พ.ศ. 2325","correct":false},{"text":"พ.ศ. 2411","correct":false}]'),
('k_king01_02', 'king_ramkhamhaeng', 'การค้าเสรีสมัยสุโขทัย', 'สุโขทัยสมัยพ่อขุนรามคำแหงส่งเสริมการค้าเสรี ''ใครใคร่ค้าช้างค้า ใครใคร่ค้าม้าค้า'' ไม่เก็บภาษีผ่านด่าน ทำให้บ้านเมืองมั่งคั่ง', 'คำว่า ''ใครใคร่ค้าช้างค้า ใครใคร่ค้าม้าค้า'' สะท้อนเรื่องใดของสุโขทัย?', '[{"text":"การค้าเสรี","correct":true},{"text":"การเก็บภาษีสูง","correct":false},{"text":"การห้ามค้าขาย","correct":false},{"text":"การทำสงคราม","correct":false}]'),
('k_king02_01', 'king_naresuan', 'วีรกรรมยุทธหัตถี', 'สมเด็จพระนเรศวรมหาราชทรงกระทำยุทธหัตถีชนะพระมหาอุปราชาบนหลังช้างศึก เมื่อ พ.ศ. 2135 เป็นวีรกรรมที่คนไทยจดจำถึงความกล้าหาญ', 'ยุทธหัตถีของสมเด็จพระนเรศวรเกิดขึ้นเมื่อ พ.ศ. ใด?', '[{"text":"พ.ศ. 2135","correct":true},{"text":"พ.ศ. 2127","correct":false},{"text":"พ.ศ. 2310","correct":false},{"text":"พ.ศ. 1826","correct":false}]'),
('k_king02_02', 'king_naresuan', 'ประกาศอิสรภาพที่เมืองแครง', 'สมเด็จพระนเรศวรมหาราชทรงประกาศอิสรภาพของกรุงศรีอยุธยาจากพม่าที่เมืองแครง เมื่อ พ.ศ. 2127 นับเป็นการกอบกู้เอกราช', 'สมเด็จพระนเรศวรทรงประกาศอิสรภาพจากชาติใด?', '[{"text":"พม่า","correct":true},{"text":"เขมร","correct":false},{"text":"จีน","correct":false},{"text":"ฝรั่งเศส","correct":false}]'),
('k_king03_01', 'king_narai', 'ยุคทองแห่งการทูต', 'รัชสมัยสมเด็จพระนารายณ์มหาราชเป็นยุคทองของวรรณคดีและการทูต ทรงส่งคณะราชทูตโกษาปานไปเจริญสัมพันธไมตรีถึงราชสำนักฝรั่งเศส', 'คณะราชทูตที่ส่งไปฝรั่งเศสในสมัยพระนารายณ์นำโดยใคร?', '[{"text":"โกษาปาน","correct":true},{"text":"โกษาเหล็ก","correct":false},{"text":"ออกญาเสนาภิมุข","correct":false},{"text":"เจ้าพระยาบวรราชนายก","correct":false}]'),
('k_king03_02', 'king_narai', 'ดาราศาสตร์ที่ลพบุรี', 'สมัยสมเด็จพระนารายณ์มีการสร้างหอดูดาวและศึกษาดาราศาสตร์ร่วมกับชาวฝรั่งเศสที่เมืองลพบุรี ซึ่งเป็นราชธานีที่สอง', 'เมืองใดเป็นราชธานีที่สองในสมัยสมเด็จพระนารายณ์?', '[{"text":"ลพบุรี","correct":true},{"text":"ธนบุรี","correct":false},{"text":"เชียงใหม่","correct":false},{"text":"นครปฐม","correct":false}]'),
('k_king04_01', 'king_taksin', 'กอบกู้เอกราชในเวลาเพียงปีเดียว', 'หลังกรุงศรีอยุธยาเสียแก่พม่า พ.ศ. 2310 สมเด็จพระเจ้าตากสินมหาราชทรงรวบรวมกำลังกอบกู้เอกราชได้ในปีเดียวกัน และสถาปนากรุงธนบุรี', 'กรุงศรีอยุธยาเสียแก่พม่าครั้งที่ 2 เมื่อ พ.ศ. ใด?', '[{"text":"พ.ศ. 2310","correct":true},{"text":"พ.ศ. 2135","correct":false},{"text":"พ.ศ. 2325","correct":false},{"text":"พ.ศ. 1826","correct":false}]'),
('k_king04_02', 'king_taksin', 'สถาปนากรุงธนบุรี', 'สมเด็จพระเจ้าตากสินมหาราชทรงสถาปนากรุงธนบุรีเป็นราชธานีริมแม่น้ำเจ้าพระยา เพื่อรวบรวมแผ่นดินไทยให้เป็นปึกแผ่นอีกครั้ง', 'กรุงธนบุรีตั้งอยู่ริมแม่น้ำใด?', '[{"text":"เจ้าพระยา","correct":true},{"text":"ท่าจีน","correct":false},{"text":"แม่กลอง","correct":false},{"text":"ป่าสัก","correct":false}]'),
('k_king05_01', 'king_rama1', 'ปฐมกษัตริย์ราชวงศ์จักรี', 'รัชกาลที่ ๑ ทรงสถาปนากรุงรัตนโกสินทร์เป็นราชธานีเมื่อ พ.ศ. 2325 ตั้งราชวงศ์จักรี และโปรดให้ชำระกฎหมายตราสามดวง', 'รัชกาลที่ ๑ ทรงสถาปนากรุงรัตนโกสินทร์เมื่อ พ.ศ. ใด?', '[{"text":"พ.ศ. 2325","correct":true},{"text":"พ.ศ. 2310","correct":false},{"text":"พ.ศ. 2411","correct":false},{"text":"พ.ศ. 1826","correct":false}]'),
('k_king05_02', 'king_rama1', 'กฎหมายตราสามดวง', 'รัชกาลที่ ๑ โปรดให้ชำระกฎหมายและประทับตรา 3 ดวง คือ ตราราชสีห์ ตราคชสีห์ และตราบัวแก้ว จึงเรียกว่า ''กฎหมายตราสามดวง''', 'กฎหมายตราสามดวงมีตราประทับกี่ดวง?', '[{"text":"3 ดวง","correct":true},{"text":"1 ดวง","correct":false},{"text":"5 ดวง","correct":false},{"text":"7 ดวง","correct":false}]'),
('k_king06_01', 'king_rama4', 'พระบิดาแห่งวิทยาศาสตร์ไทย', 'รัชกาลที่ ๔ ทรงคำนวณการเกิดสุริยุปราคาเต็มดวงที่ตำบลหว้ากอได้อย่างแม่นยำล่วงหน้า 2 ปี เมื่อ พ.ศ. 2411', 'รัชกาลที่ ๔ ทรงคำนวณปรากฏการณ์ทางดาราศาสตร์ใดได้อย่างแม่นยำ?', '[{"text":"สุริยุปราคา","correct":true},{"text":"จันทรุปราคา","correct":false},{"text":"แผ่นดินไหว","correct":false},{"text":"น้ำขึ้นน้ำลง","correct":false}]'),
('k_king06_02', 'king_rama4', 'สุริยุปราคาที่หว้ากอ', 'รัชกาลที่ ๔ เสด็จทอดพระเนตรสุริยุปราคาเต็มดวงที่ตำบลหว้ากอ จังหวัดประจวบคีรีขันธ์ เมื่อ พ.ศ. 2411 ตามที่ทรงคำนวณไว้', 'สุริยุปราคาที่รัชกาลที่ ๔ เสด็จทอดพระเนตรเกิดที่จังหวัดใด?', '[{"text":"ประจวบคีรีขันธ์","correct":true},{"text":"เพชรบุรี","correct":false},{"text":"ชุมพร","correct":false},{"text":"ระยอง","correct":false}]'),
('k_king07_01', 'king_rama5', 'พระปิยมหาราชผู้เลิกทาส', 'รัชกาลที่ ๕ ทรงเลิกทาสอย่างค่อยเป็นค่อยไปโดยไม่เสียเลือดเนื้อ พร้อมปฏิรูปการปกครองและริเริ่มการรถไฟ ไปรษณีย์ ให้ประเทศทันสมัย', 'พระนาม ''พระปิยมหาราช'' ของรัชกาลที่ ๕ มีความหมายว่าอย่างไร?', '[{"text":"มหาราชผู้เป็นที่รักของประชาชน","correct":true},{"text":"มหาราชนักรบ","correct":false},{"text":"มหาราชนักปราชญ์","correct":false},{"text":"มหาราชผู้สร้างเมือง","correct":false}]'),
('k_king07_02', 'king_rama5', 'การรถไฟและไปรษณีย์', 'รัชกาลที่ ๕ ทรงริเริ่มกิจการรถไฟ ไปรษณีย์ และโทรเลข เพื่อพัฒนาประเทศให้ทันสมัยและเชื่อมโยงหัวเมืองต่าง ๆ เข้าด้วยกัน', 'สาธารณูปโภคสมัยใหม่ใดที่ริเริ่มขึ้นในรัชสมัยรัชกาลที่ ๕?', '[{"text":"การรถไฟ","correct":true},{"text":"รถไฟฟ้าใต้ดิน","correct":false},{"text":"สนามบิน","correct":false},{"text":"โทรทัศน์","correct":false}]');
INSERT INTO gold_quiz (id, king_id, difficulty, reward, time_limit_sec, question, choices, explanation)
INSERT INTO subject_quiz (id, king_id, subject, difficulty, reward, time_limit_sec, question, choices, explanation) VALUES
('sub_ramkhamhaeng_social', 'king_ramkhamhaeng', 'social', 'easy', 50, 25, 'พ่อขุนรามคำแหงมหาราชทรงประดิษฐ์สิ่งใดที่เป็นรากฐานของภาษาไทยปัจจุบัน?', '[{"text":"อักษรไทย (ลายสือไทย)","correct":true},{"text":"อักษรขอม","correct":false},{"text":"อักษรมอญ","correct":false},{"text":"อักษรจีน","correct":false}]', 'ทรงประดิษฐ์ลายสือไทเมื่อ พ.ศ. 1826 เป็นต้นแบบของอักษรไทยที่ใช้อยู่ในปัจจุบัน'),
('sub_ramkhamhaeng_math', 'king_ramkhamhaeng', 'math', 'medium', 50, 30, 'ศิลาจารึกหลักที่ 1 มีอายุราว พ.ศ. 1835 หากปัจจุบันคือ พ.ศ. 2567 ศิลาจารึกมีอายุประมาณกี่ปี?', '[{"text":"732 ปี","correct":true},{"text":"632 ปี","correct":false},{"text":"832 ปี","correct":false},{"text":"700 ปี","correct":false}]', 'คำนวณจาก 2567 − 1835 = 732 ปี'),
('sub_ramkhamhaeng_science', 'king_ramkhamhaeng', 'science', 'easy', 50, 25, 'เหตุใดข้อความบนศิลาจารึกหินจึงคงอยู่ได้นานหลายร้อยปี?', '[{"text":"เพราะหินแข็งและทนต่อการผุกร่อน","correct":true},{"text":"เพราะหินเบา","correct":false},{"text":"เพราะหินละลายน้ำได้","correct":false},{"text":"เพราะหินนำไฟฟ้า","correct":false}]', 'หินเป็นวัสดุที่แข็งแรงและทนต่อลม ฝน แดด จึงเก็บรักษาข้อมูลได้นาน'),
('sub_ramkhamhaeng_art', 'king_ramkhamhaeng', 'art', 'medium', 50, 25, 'เจดีย์ทรงพุ่มข้าวบิณฑ์ (ทรงดอกบัวตูม) เป็นเอกลักษณ์ของศิลปะสมัยใด?', '[{"text":"สุโขทัย","correct":true},{"text":"อยุธยา","correct":false},{"text":"รัตนโกสินทร์","correct":false},{"text":"ล้านนา","correct":false}]', 'เจดีย์ทรงพุ่มข้าวบิณฑ์เป็นสถาปัตยกรรมเด่นของศิลปะสุโขทัย'),
('sub_ramkhamhaeng_health_pe', 'king_ramkhamhaeng', 'health_pe', 'easy', 50, 25, 'กีฬาและศิลปะการต่อสู้ประจำชาติไทยที่สืบทอดมาแต่โบราณคือข้อใด?', '[{"text":"มวยไทย","correct":true},{"text":"กอล์ฟ","correct":false},{"text":"เทนนิส","correct":false},{"text":"สเก็ตน้ำแข็ง","correct":false}]', 'มวยไทยเป็นศิลปะการต่อสู้และการออกกำลังกายที่อยู่คู่คนไทยมาช้านาน'),
('sub_ramkhamhaeng_foreign_language', 'king_ramkhamhaeng', 'foreign_language', 'easy', 50, 25, 'คำภาษาอังกฤษว่า ''stone'' ตรงกับคำไทยว่าอะไร (เกี่ยวกับศิลาจารึก)?', '[{"text":"หิน","correct":true},{"text":"น้ำ","correct":false},{"text":"ไม้","correct":false},{"text":"ดิน","correct":false}]', 'stone แปลว่า หิน ซึ่งเป็นวัสดุที่ใช้ทำศิลาจารึก'),
('sub_naresuan_social', 'king_naresuan', 'social', 'easy', 50, 25, 'สมเด็จพระนเรศวรมหาราชทรงประกาศอิสรภาพให้กรุงศรีอยุธยาพ้นจากการเป็นเมืองขึ้นของชาติใด?', '[{"text":"พม่า","correct":true},{"text":"เขมร","correct":false},{"text":"จีน","correct":false},{"text":"ฝรั่งเศส","correct":false}]', 'ทรงประกาศอิสรภาพจากพม่าเมื่อ พ.ศ. 2127'),
('sub_naresuan_math', 'king_naresuan', 'math', 'medium', 50, 30, 'พระนเรศวรประกาศอิสรภาพ พ.ศ. 2127 และทรงกระทำยุทธหัตถี พ.ศ. 2135 เหตุการณ์สองอย่างนี้ห่างกันกี่ปี?', '[{"text":"8 ปี","correct":true},{"text":"5 ปี","correct":false},{"text":"10 ปี","correct":false},{"text":"12 ปี","correct":false}]', 'คำนวณจาก 2135 − 2127 = 8 ปี'),
('sub_naresuan_science', 'king_naresuan', 'science', 'medium', 50, 25, 'ยุทธหัตถีคือการต่อสู้บนหลังช้าง ช้างจัดอยู่ในสัตว์กลุ่มใด?', '[{"text":"สัตว์เลี้ยงลูกด้วยนม","correct":true},{"text":"สัตว์เลื้อยคลาน","correct":false},{"text":"สัตว์ปีก","correct":false},{"text":"สัตว์ครึ่งบกครึ่งน้ำ","correct":false}]', 'ช้างเป็นสัตว์เลี้ยงลูกด้วยนม ออกลูกเป็นตัวและเลี้ยงลูกด้วยนม'),
('sub_naresuan_art', 'king_naresuan', 'art', 'medium', 50, 25, 'อนุสรณ์สถานที่สร้างขึ้นเพื่อรำลึกวีรกรรมยุทธหัตถีของสมเด็จพระนเรศวรคือข้อใด?', '[{"text":"พระเจดีย์ยุทธหัตถี (ดอนเจดีย์) จ.สุพรรณบุรี","correct":true},{"text":"พระธาตุพนม","correct":false},{"text":"พระบรมธาตุนครศรีธรรมราช","correct":false},{"text":"วัดอรุณราชวราราม","correct":false}]', 'พระเจดีย์ยุทธหัตถีที่ดอนเจดีย์ จังหวัดสุพรรณบุรี สร้างเพื่อรำลึกชัยชนะยุทธหัตถี'),
('sub_naresuan_health_pe', 'king_naresuan', 'health_pe', 'easy', 50, 25, 'ศิลปะการต่อสู้ป้องกันตัวที่นักรบไทยสมัยอยุธยาฝึกฝนเพื่อใช้ในสงครามคือข้อใด?', '[{"text":"มวยไทย","correct":true},{"text":"ยูโด","correct":false},{"text":"คาราเต้","correct":false},{"text":"เทควันโด","correct":false}]', 'มวยไทยเป็นศิลปะการต่อสู้ที่นักรบไทยฝึกเพื่อใช้ในการสงคราม'),
('sub_naresuan_foreign_language', 'king_naresuan', 'foreign_language', 'easy', 50, 25, 'คำว่า ''freedom'' ในภาษาอังกฤษ ตรงกับคำไทยว่าอะไร (เช่น การประกาศ___ ของพระนเรศวร)?', '[{"text":"อิสรภาพ","correct":true},{"text":"สงคราม","correct":false},{"text":"การค้า","correct":false},{"text":"ความพ่ายแพ้","correct":false}]', 'freedom แปลว่า อิสรภาพ ตรงกับการประกาศอิสรภาพของสมเด็จพระนเรศวร'),
('sub_narai_social', 'king_narai', 'social', 'easy', 50, 25, 'สมเด็จพระนารายณ์มหาราชทรงส่งคณะราชทูต (โกษาปาน) ไปเจริญสัมพันธไมตรีกับประเทศใด?', '[{"text":"ฝรั่งเศส","correct":true},{"text":"อังกฤษ","correct":false},{"text":"จีน","correct":false},{"text":"ญี่ปุ่น","correct":false}]', 'ทรงส่งออกญาโกษาปานไปเข้าเฝ้าพระเจ้าหลุยส์ที่ 14 แห่งฝรั่งเศส'),
('sub_narai_math', 'king_narai', 'math', 'medium', 50, 30, 'สมเด็จพระนารายณ์มหาราชครองราชย์ พ.ศ. 2199–2231 รวมครองราชย์กี่ปี?', '[{"text":"32 ปี","correct":true},{"text":"30 ปี","correct":false},{"text":"25 ปี","correct":false},{"text":"40 ปี","correct":false}]', 'คำนวณจาก 2231 − 2199 = 32 ปี'),
('sub_narai_science', 'king_narai', 'science', 'medium', 50, 25, 'ปรากฏการณ์ที่ดวงอาทิตย์หรือดวงจันทร์ถูกบดบัง ซึ่งมีการสังเกตที่ลพบุรีสมัยพระนารายณ์ เรียกว่าอะไร?', '[{"text":"อุปราคา (สุริยุปราคา/จันทรุปราคา)","correct":true},{"text":"แผ่นดินไหว","correct":false},{"text":"น้ำขึ้นน้ำลง","correct":false},{"text":"ฟ้าร้อง","correct":false}]', 'สมัยพระนารายณ์มีการดูอุปราคาที่ลพบุรีร่วมกับนักดาราศาสตร์ชาวฝรั่งเศส'),
('sub_narai_art', 'king_narai', 'art', 'medium', 50, 25, 'รัชสมัยสมเด็จพระนารายณ์เป็นยุคทองของวรรณคดี กวีเอกคนสำคัญในสมัยนี้คือใคร?', '[{"text":"ศรีปราชญ์","correct":true},{"text":"สุนทรภู่","correct":false},{"text":"ศรีธนญชัย","correct":false},{"text":"เจ้าฟ้าธรรมธิเบศร","correct":false}]', 'ศรีปราชญ์และพระโหราธิบดีเป็นกวีเอกในสมัยสมเด็จพระนารายณ์ (สุนทรภู่อยู่สมัยรัตนโกสินทร์)'),
('sub_narai_health_pe', 'king_narai', 'health_pe', 'easy', 50, 25, 'ภูมิปัญญาไทยด้านการดูแลสุขภาพด้วยสมุนไพรที่สืบทอดมาแต่โบราณ จัดอยู่ในศาสตร์ใด?', '[{"text":"การแพทย์แผนไทย","correct":true},{"text":"การเดินเรือ","correct":false},{"text":"ดาราศาสตร์","correct":false},{"text":"การก่อสร้าง","correct":false}]', 'การใช้สมุนไพรรักษาโรคเป็นภูมิปัญญาการแพทย์แผนไทยที่ช่วยดูแลสุขภาพ'),
('sub_narai_foreign_language', 'king_narai', 'foreign_language', 'easy', 50, 25, 'คำว่า ''France'' หมายถึงประเทศใด (ชาติที่สมเด็จพระนารายณ์ทรงเจริญสัมพันธไมตรี)?', '[{"text":"ฝรั่งเศส","correct":true},{"text":"อังกฤษ","correct":false},{"text":"โปรตุเกส","correct":false},{"text":"เนเธอร์แลนด์","correct":false}]', 'France คือประเทศฝรั่งเศส ที่พระนารายณ์ทรงส่งราชทูตไปเจริญสัมพันธไมตรี'),
('sub_taksin_social', 'king_taksin', 'social', 'easy', 50, 25, 'สมเด็จพระเจ้าตากสินมหาราชทรงกอบกู้เอกราชแล้วสถาปนาราชธานีใหม่ที่ใด?', '[{"text":"กรุงธนบุรี","correct":true},{"text":"กรุงศรีอยุธยา","correct":false},{"text":"กรุงสุโขทัย","correct":false},{"text":"กรุงเทพมหานคร","correct":false}]', 'ทรงสถาปนากรุงธนบุรีเป็นราชธานีหลังกอบกู้เอกราชเมื่อ พ.ศ. 2310'),
('sub_taksin_math', 'king_taksin', 'math', 'medium', 50, 30, 'กรุงธนบุรีเป็นราชธานีตั้งแต่ พ.ศ. 2310 ถึง พ.ศ. 2325 รวมเป็นราชธานีนานกี่ปี?', '[{"text":"15 ปี","correct":true},{"text":"10 ปี","correct":false},{"text":"20 ปี","correct":false},{"text":"25 ปี","correct":false}]', 'คำนวณจาก 2325 − 2310 = 15 ปี'),
('sub_taksin_science', 'king_taksin', 'science', 'medium', 50, 25, 'กองทัพเรือสมัยกรุงธนบุรีใช้เรือเดินทางทางน้ำ เรือลอยน้ำได้เพราะหลักการทางวิทยาศาสตร์ข้อใด?', '[{"text":"แรงลอยตัว (แรงพยุงของน้ำ)","correct":true},{"text":"แรงแม่เหล็ก","correct":false},{"text":"แสงอาทิตย์","correct":false},{"text":"ลมพายุ","correct":false}]', 'น้ำมีแรงพยุง (แรงลอยตัว) ดันวัตถุขึ้น ทำให้เรือลอยน้ำได้'),
('sub_taksin_art', 'king_taksin', 'art', 'easy', 50, 25, 'กรุงธนบุรีตั้งอยู่ริมแม่น้ำใด ซึ่งมีวัดอรุณราชวรารามเป็นวัดสำคัญ?', '[{"text":"แม่น้ำเจ้าพระยา","correct":true},{"text":"แม่น้ำโขง","correct":false},{"text":"แม่น้ำปิง","correct":false},{"text":"แม่น้ำน่าน","correct":false}]', 'กรุงธนบุรีตั้งอยู่ริมแม่น้ำเจ้าพระยา บริเวณที่ตั้งวัดอรุณราชวราราม'),
('sub_taksin_health_pe', 'king_taksin', 'health_pe', 'medium', 50, 25, 'มวยไทยใช้ส่วนใดของร่างกายเป็นอาวุธ ตามคำเรียก "นวอาวุธ" (8 อาวุธ)?', '[{"text":"หมัด ศอก เข่า และเท้า","correct":true},{"text":"เฉพาะหมัด","correct":false},{"text":"เฉพาะเท้า","correct":false},{"text":"ใช้ดาบและโล่","correct":false}]', 'มวยไทยใช้หมัด ศอก เข่า เท้า เป็นอาวุธ จึงเรียกว่าศิลปะแห่งนวอาวุธ (8 อาวุธ)'),
('sub_taksin_foreign_language', 'king_taksin', 'foreign_language', 'easy', 50, 25, 'คำว่า ''king'' ในภาษาอังกฤษ ตรงกับตำแหน่งใดของสมเด็จพระเจ้าตากสิน?', '[{"text":"พระมหากษัตริย์","correct":true},{"text":"ทหาร","correct":false},{"text":"พ่อค้า","correct":false},{"text":"ชาวนา","correct":false}]', 'king แปลว่า พระมหากษัตริย์ หรือพระราชา'),
('sub_rama1_social', 'king_rama1', 'social', 'easy', 50, 25, 'พระบาทสมเด็จพระพุทธยอดฟ้าจุฬาโลกมหาราช (รัชกาลที่ 1) ทรงสถาปนากรุงรัตนโกสินทร์ (กรุงเทพฯ) เมื่อ พ.ศ. ใด?', '[{"text":"พ.ศ. 2325","correct":true},{"text":"พ.ศ. 2310","correct":false},{"text":"พ.ศ. 2394","correct":false},{"text":"พ.ศ. 2411","correct":false}]', 'ทรงสถาปนากรุงรัตนโกสินทร์เป็นราชธานีและตั้งราชวงศ์จักรีเมื่อ พ.ศ. 2325'),
('sub_rama1_math', 'king_rama1', 'math', 'medium', 50, 30, 'กรุงรัตนโกสินทร์สถาปนาเมื่อ พ.ศ. 2325 หากปัจจุบันคือ พ.ศ. 2567 กรุงเทพฯ มีอายุกี่ปี?', '[{"text":"242 ปี","correct":true},{"text":"200 ปี","correct":false},{"text":"252 ปี","correct":false},{"text":"300 ปี","correct":false}]', 'คำนวณจาก 2567 − 2325 = 242 ปี'),
('sub_rama1_science', 'king_rama1', 'science', 'medium', 50, 25, 'การก่อสร้างพระบรมมหาราชวังในอดีตใช้ "ปูน" ซึ่งได้จากการเผาสิ่งใด?', '[{"text":"หินปูนหรือเปลือกหอย","correct":true},{"text":"เม็ดทราย","correct":false},{"text":"แผ่นเหล็ก","correct":false},{"text":"ท่อนไม้","correct":false}]', 'ปูนขาวได้จากการเผาหินปูนหรือเปลือกหอย เป็นความรู้ทางวิทยาศาสตร์เรื่องการเปลี่ยนแปลงของสาร'),
('sub_rama1_art', 'king_rama1', 'art', 'medium', 50, 25, 'วรรณคดีเรื่องใดที่พระบาทสมเด็จพระพุทธยอดฟ้าจุฬาโลกมหาราชทรงพระราชนิพนธ์ (ฉบับสมบูรณ์)?', '[{"text":"รามเกียรติ์","correct":true},{"text":"พระอภัยมณี","correct":false},{"text":"ขุนช้างขุนแผน","correct":false},{"text":"อิเหนา","correct":false}]', 'รัชกาลที่ 1 ทรงพระราชนิพนธ์บทละครเรื่องรามเกียรติ์ฉบับสมบูรณ์ (พระอภัยมณีเป็นผลงานสุนทรภู่)'),
('sub_rama1_health_pe', 'king_rama1', 'health_pe', 'easy', 50, 25, 'การเล่นว่าวและตะกร้อซึ่งเป็นการละเล่นไทย ช่วยพัฒนาด้านใดเป็นหลัก?', '[{"text":"การออกกำลังกายและความคล่องแคล่ว","correct":true},{"text":"การอ่านหนังสือ","correct":false},{"text":"การวาดภาพ","correct":false},{"text":"การคำนวณเลข","correct":false}]', 'การละเล่นไทยอย่างว่าวและตะกร้อช่วยให้ร่างกายแข็งแรงและคล่องแคล่ว'),
('sub_rama1_foreign_language', 'king_rama1', 'foreign_language', 'easy', 50, 25, 'คำว่า ''temple'' ในภาษาอังกฤษ ตรงกับคำไทยว่าอะไร (เช่น วัดพระแก้วที่รัชกาลที่ 1 ทรงสร้าง)?', '[{"text":"วัด","correct":true},{"text":"วัง","correct":false},{"text":"บ้าน","correct":false},{"text":"โรงเรียน","correct":false}]', 'temple แปลว่า วัด เช่น Temple of the Emerald Buddha คือวัดพระแก้ว'),
('sub_rama4_social', 'king_rama4', 'social', 'medium', 50, 25, 'พระบาทสมเด็จพระจอมเกล้าเจ้าอยู่หัว (รัชกาลที่ 4) ทรงลงนามสนธิสัญญาเปิดการค้ากับอังกฤษ ชื่อสนธิสัญญาใด?', '[{"text":"สนธิสัญญาเบาว์ริง","correct":true},{"text":"สนธิสัญญาเบอร์นี","correct":false},{"text":"สนธิสัญญาปารีส","correct":false},{"text":"สนธิสัญญาเจนีวา","correct":false}]', 'สนธิสัญญาเบาว์ริงลงนามกับอังกฤษเมื่อ พ.ศ. 2398 เปิดการค้าเสรีกับตะวันตก'),
('sub_rama4_math', 'king_rama4', 'math', 'medium', 50, 30, 'รัชกาลที่ 4 เสด็จทอดพระเนตรสุริยุปราคาที่หว้ากอเมื่อ พ.ศ. 2411 หากปัจจุบันคือ พ.ศ. 2567 ผ่านมากี่ปี?', '[{"text":"156 ปี","correct":true},{"text":"100 ปี","correct":false},{"text":"200 ปี","correct":false},{"text":"146 ปี","correct":false}]', 'คำนวณจาก 2567 − 2411 = 156 ปี'),
('sub_rama4_science', 'king_rama4', 'science', 'easy', 50, 25, 'รัชกาลที่ 4 ได้รับยกย่องเป็น "พระบิดาแห่งวิทยาศาสตร์ไทย" จากการคำนวณปรากฏการณ์ใดได้อย่างแม่นยำ?', '[{"text":"สุริยุปราคาเต็มดวง","correct":true},{"text":"แผ่นดินไหว","correct":false},{"text":"น้ำท่วมใหญ่","correct":false},{"text":"พายุหมุน","correct":false}]', 'ทรงคำนวณการเกิดสุริยุปราคาเต็มดวงที่หว้ากอได้ล่วงหน้าอย่างแม่นยำ เมื่อ พ.ศ. 2411'),
('sub_rama4_art', 'king_rama4', 'art', 'medium', 50, 25, 'ในสมัยรัชกาลที่ 4 เริ่มมีการนำเทคโนโลยีตะวันตกใดมาใช้บันทึกภาพเหมือนจริงเป็นครั้งแรก ๆ ในไทย?', '[{"text":"การถ่ายภาพ (กล้องถ่ายรูป)","correct":true},{"text":"โทรทัศน์","correct":false},{"text":"ภาพยนตร์เสียง","correct":false},{"text":"คอมพิวเตอร์","correct":false}]', 'การถ่ายภาพด้วยกล้องถ่ายรูปเริ่มแพร่หลายในราชสำนักไทยสมัยรัชกาลที่ 4'),
('sub_rama4_health_pe', 'king_rama4', 'health_pe', 'medium', 50, 25, 'ในสมัยรัชกาลที่ 4–5 เริ่มมีการแพทย์แบบตะวันตกเข้ามา วิธีป้องกันโรคระบาดที่ดีที่สุดคือข้อใด?', '[{"text":"รักษาความสะอาดและฉีดวัคซีน","correct":true},{"text":"อดอาหาร","correct":false},{"text":"ไม่ออกกำลังกาย","correct":false},{"text":"นอนดึกเป็นประจำ","correct":false}]', 'การรักษาความสะอาดและการฉีดวัคซีนช่วยป้องกันโรคระบาดได้อย่างมีประสิทธิภาพ'),
('sub_rama4_foreign_language', 'king_rama4', 'foreign_language', 'easy', 50, 25, 'รัชกาลที่ 4 ทรงรอบรู้ภาษาต่างประเทศ ภาษาใดที่ทรงใช้ติดต่อกับชาติตะวันตกและทรงเชี่ยวชาญ?', '[{"text":"ภาษาอังกฤษ","correct":true},{"text":"ภาษาญี่ปุ่น","correct":false},{"text":"ภาษาเกาหลี","correct":false},{"text":"ภาษารัสเซีย","correct":false}]', 'ทรงเชี่ยวชาญภาษาอังกฤษและภาษาละติน ใช้ติดต่อสื่อสารกับชาวตะวันตก'),
('sub_rama5_social', 'king_rama5', 'social', 'easy', 50, 25, 'พระราชกรณียกิจสำคัญด้านมนุษยธรรมของรัชกาลที่ 5 ที่ทำให้ได้รับพระนาม "พระปิยมหาราช" คือข้อใด?', '[{"text":"การเลิกทาส","correct":true},{"text":"การสร้างกำแพงเมือง","correct":false},{"text":"การเพิ่มภาษี","correct":false},{"text":"การปิดประเทศ","correct":false}]', 'ทรงเลิกทาสอย่างค่อยเป็นค่อยไปโดยไม่เสียเลือดเนื้อ จึงได้รับพระนามพระปิยมหาราช'),
('sub_rama5_math', 'king_rama5', 'math', 'medium', 50, 30, 'รัชกาลที่ 5 ทรงเปิดการรถไฟหลวงสายแรก (กรุงเทพฯ–อยุธยา) เมื่อ พ.ศ. 2439 หากปัจจุบันคือ พ.ศ. 2567 รถไฟไทยมีอายุกี่ปี?', '[{"text":"128 ปี","correct":true},{"text":"100 ปี","correct":false},{"text":"150 ปี","correct":false},{"text":"118 ปี","correct":false}]', 'คำนวณจาก 2567 − 2439 = 128 ปี'),
('sub_rama5_science', 'king_rama5', 'science', 'medium', 50, 25, 'รัชกาลที่ 5 ทรงนำการสื่อสารสมัยใหม่เข้ามา อุปกรณ์ที่ส่งข้อความทางไกลด้วยสัญญาณไฟฟ้าในสมัยนั้นคือข้อใด?', '[{"text":"โทรเลข","correct":true},{"text":"โทรทัศน์","correct":false},{"text":"อินเทอร์เน็ต","correct":false},{"text":"วิทยุติดตามตัว","correct":false}]', 'โทรเลขส่งข้อความทางไกลด้วยสัญญาณไฟฟ้า เป็นเทคโนโลยีการสื่อสารที่เริ่มในสมัยรัชกาลที่ 5'),
('sub_rama5_art', 'king_rama5', 'art', 'medium', 50, 25, 'พระที่นั่งที่สร้างสมัยรัชกาลที่ 5 ด้วยสถาปัตยกรรมตะวันตกและใช้หินอ่อน คือพระที่นั่งใด?', '[{"text":"พระที่นั่งอนันตสมาคม","correct":true},{"text":"พระที่นั่งดุสิตมหาปราสาท","correct":false},{"text":"ปราสาทพระเทพบิดร","correct":false},{"text":"พระที่นั่งอมรินทรวินิจฉัย","correct":false}]', 'พระที่นั่งอนันตสมาคมสร้างด้วยหินอ่อนแบบสถาปัตยกรรมตะวันตก เริ่มในสมัยรัชกาลที่ 5'),
('sub_rama5_health_pe', 'king_rama5', 'health_pe', 'easy', 50, 25, 'กีฬาชนิดใดที่นำเข้าจากตะวันตกและเริ่มนิยมเล่นในโรงเรียนและสนามหลวงสมัยรัชกาลที่ 5?', '[{"text":"ฟุตบอล","correct":true},{"text":"อเมริกันฟุตบอล","correct":false},{"text":"เบสบอล","correct":false},{"text":"ฮอกกี้น้ำแข็ง","correct":false}]', 'ฟุตบอลเริ่มเข้ามาและได้รับความนิยมในไทยช่วงปลายรัชกาลที่ 5'),
('sub_rama5_foreign_language', 'king_rama5', 'foreign_language', 'easy', 50, 25, 'รัชกาลที่ 5 เสด็จประพาส ''Europe'' เพื่อเจริญสัมพันธไมตรี คำว่า Europe หมายถึงอะไร?', '[{"text":"ทวีปยุโรป","correct":true},{"text":"ทวีปเอเชีย","correct":false},{"text":"ทวีปแอฟริกา","correct":false},{"text":"ทวีปอเมริกา","correct":false}]', 'Europe คือทวีปยุโรป ที่รัชกาลที่ 5 เสด็จประพาสเพื่อเจริญสัมพันธไมตรี');
INSERT INTO app_config (config_key, config_value)
